+      await repo.saveAthleteProfile(const AthleteProfile(role: 'coach'));
+
+      final repo2 = await PrefsRepository.create();
+      expect(repo2.loadAthleteProfile().role, 'coach');
+      expect(repo2.loadAthleteProfile().isCoach, isTrue);
+    });
+
