148	  const StartupSyncedClickerScreen({
149	    super.key,
150	    this.startupSyncBuilder,
151	    this.foregroundSyncBuilder,
152	    this.enableBackgroundTasks = true,
153	  });
154	
155	  final Future<void> Function()? startupSyncBuilder;
156	  final Future<void> Function()? foregroundSyncBuilder;
157	  final bool enableBackgroundTasks;
158	
159	  @override
160	  State<StartupSyncedClickerScreen> createState() =>
161	      _StartupSyncedClickerScreenState();
162	}
163	
164	class _StartupSyncedClickerScreenState
165	    extends State<StartupSyncedClickerScreen> with WidgetsBindingObserver {
166	  late final Future<void> _startupSync;
167	  var _startupFinished = false;
168	  var _foregroundSyncRunning = false;
169	
170	  @override
171	  void initState() {
172	    super.initState();
173	    WidgetsBinding.instance.addObserver(this);
174	    _startupSync = (widget.startupSyncBuilder ?? _syncStartupSync)();
175	    _startupSync.whenComplete(() {
176	      _startupFinished = true;
177	    });
178	  }
179	
180	  @override
181	  void dispose() {
182	    WidgetsBinding.instance.removeObserver(this);
183	    super.dispose();
184	  }
185	
186	  @override
187	  void didChangeAppLifecycleState(AppLifecycleState state) {
188	    if (state != AppLifecycleState.resumed) return;
189	    _retryPendingSyncIfNeeded();
190	  }
191	
192	  Future<void> _syncStartupSync() async {
193	    try {
194	      final repo = await PrefsRepository.create();
195	      await CloudSettingsService().syncLocalAndRemote(repo);
196	      final enabled = await repo.isSyncHistoryEnabled();
197	      if (!enabled) return;
198	
199	      await CloudHistoryService().syncLocalAndRemote(repo);
200	    } catch (e) {
201	      debugPrint('Startup history sync error: $e');
202	    }
203	  }
204	
205	  Future<void> _retryPendingSyncIfNeeded() async {
206	    if (!_startupFinished || _foregroundSyncRunning) return;
207	    _foregroundSyncRunning = true;
208	    try {
209	      await (widget.foregroundSyncBuilder ?? _syncPendingSync)();
210	    } catch (e) {
211	      debugPrint('Foreground sync error: $e');
212	    } finally {
213	      _foregroundSyncRunning = false;
214	    }
215	  }
216	
217	  Future<void> _syncPendingSync() async {
218	    try {
219	      final repo = await PrefsRepository.create();
220	      if (!repo.isSyncPending()) return;
221	
222	      await CloudSettingsService().syncLocalAndRemote(repo);
223	      if (await repo.isSyncHistoryEnabled()) {
224	        await CloudHistoryService().syncLocalAndRemote(repo);
225	      }
226	    } catch (e) {
227	      debugPrint('Foreground pending sync retry error: $e');
228	    }
229	  }
230	
231	  @override
232	  Widget build(BuildContext context) {
233	    return FutureBuilder<void>(
234	      future: _startupSync,
235	      builder: (context, snapshot) {
236	        if (snapshot.connectionState != ConnectionState.done) {
237	          return const Scaffold(
238	            key: AuthGateKeys.loadingScreenKey,
239	            body: Center(child: CircularProgressIndicator()),
240	          );
241	        }
242	
243	        return ClickerScreen(
244	          key: AuthGateKeys.clickerScreenKey,
245	          enableBackgroundTasks: widget.enableBackgroundTasks,
246	        );
247	      },
248	    );
249	  }
250	}

