    59	            isCoach: isCoach,
    60	          ),
    61	        );
    62	      },
    63	    );
    64	  }
    65	
    66	  void _showExportOptions(BuildContext context, bool isCoach) {
    67	    final l10n = AppLocalizations.of(context);
    68	
    69	    showModalBottomSheet<void>(
    70	      context: context,
    71	      showDragHandle: true,
    72	      constraints: const BoxConstraints(maxWidth: 420),
    73	      shape: const RoundedRectangleBorder(
    74	        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
    75	      ),
    76	      builder: (sheetContext) => SafeArea(
    77	        child: ListView(
    78	          shrinkWrap: true,
    79	          children: [
    80	            ListTile(
    81	              leading: const Icon(Icons.ios_share),
    82	              title: Text(l10n.precisionReport),
    83	              subtitle: Text(session.name),
    84	            ),
    85	            ListTile(
    86	              leading: const Icon(Icons.ios_share),
    87	              title: Text(l10n.shareTextReport),
    88	              onTap: () {
    89	                Navigator.pop(sheetContext);
    90	                _shareTextReport(context, isCoach);
    91	              },
    92	            ),
    93	            ListTile(
    94	              leading: const Icon(Icons.table_chart),
    95	              title: Text(l10n.shareCsvReport),
    96	              onTap: () {
    97	                Navigator.pop(sheetContext);
    98	                _shareCsvReport(context, isCoach);
    99	              },
   100	            ),
   101	            ListTile(
   102	              leading: const Icon(Icons.copy),
   103	              title: Text(l10n.copyCsvReport),
   104	              onTap: () {
   105	                Navigator.pop(sheetContext);
   106	                _copyCsvReport(context, isCoach);
   107	              },
   108	            ),
   109	          ],
   110	        ),
   111	      ),
   112	    );
   113	  }
   114	
   115	  Future<void> _shareTextReport(BuildContext context, bool isCoach) async {
   116	    final l10n = AppLocalizations.of(context);
   117	    await _shareOrCopy(
   118	      context,
   119	      text: ReportExporter.buildPlainText(
   120	        session,
   121	        l10n: l10n,
   122	        tuning: tuning,
   123	        isCoach: isCoach,
   124	      ),
   125	      debugLabel: l10n.shareTextReport,
   126	      successMessage: l10n.reportShared,
   127	      fallbackMessage: l10n.reportCopied,
   128	    );
   129	  }
   130	
   131	  Future<void> _shareCsvReport(BuildContext context, bool isCoach) async {
   132	    final l10n = AppLocalizations.of(context);
   133	    await _shareOrCopy(
   134	      context,
   135	      text: ReportExporter.buildCsv(
   136	        session,
   137	        l10n: l10n,
   138	        tuning: tuning,
   139	        isCoach: isCoach,
   140	      ),
   141	      debugLabel: l10n.shareCsvReport,
   142	      successMessage: l10n.csvShared,
   143	      fallbackMessage: l10n.csvCopied,
   144	    );
   145	  }
   146	
   147	  Future<void> _copyCsvReport(BuildContext context, bool isCoach) async {
   148	    final l10n = AppLocalizations.of(context);
   149	    await Clipboard.setData(
   150	      ClipboardData(
   151	        text: ReportExporter.buildCsv(
   152	          session,
   153	          l10n: l10n,
   154	          tuning: tuning,
   155	          isCoach: isCoach,
   156	        ),
   157	      ),
   158	    );
   159	    if (!context.mounted) return;
   160	    ScaffoldMessenger.of(
   161	      context,
   162	    ).showSnackBar(SnackBar(content: Text(l10n.csvCopied)));
   163	  }
   164	
   165	  Future<void> _shareOrCopy(
   166	    BuildContext context, {
   167	    required String text,
   168	    required String debugLabel,
   169	    required String successMessage,
   170	    required String fallbackMessage,
   171	  }) async {
   172	    try {
   173	      final result = await SharePlus.instance.share(
   174	        ShareParams(subject: session.name, text: text),
   175	      );
   176	      if (result.status == ShareResultStatus.success) {
   177	        if (!context.mounted) return;
   178	        ScaffoldMessenger.of(
   179	          context,
   180	        ).showSnackBar(SnackBar(content: Text(successMessage)));
   181	        return;
   182	      }
   183	      if (result.status == ShareResultStatus.dismissed) return;
   184	    } catch (e) {
   185	      debugPrint('$debugLabel error: $e');
   186	    }
   187	
   188	    await Clipboard.setData(ClipboardData(text: text));
   189	    if (!context.mounted) return;
   190	    ScaffoldMessenger.of(
   191	      context,
   192	    ).showSnackBar(SnackBar(content: Text(fallbackMessage)));
   193	  }
