   207	              status: l10n.green,
   208	              color: Colors.green,
   209	              description: l10n.greenDescription,
   210	            ),
   211	            _InfoRow(
   212	              status: l10n.orange,
   213	              color: Colors.orange,
   214	              description: l10n.orangeDescription,
   215	            ),
   216	            _InfoRow(
   217	              status: l10n.red,
   218	              color: Colors.red,
   219	              description: l10n.redDescription,
   220	            ),
   221	            _InfoRow(
   222	              status: l10n.grey,
   223	              color: Colors.grey,
   224	              description: l10n.greyDescription,
   225	            ),
   226	          ],
   227	        ),
   228	        actions: [
   229	          TextButton(onPressed: () => Navigator.pop(ctx), child: Text(l10n.ok)),
   230	        ],
   231	      ),
   232	    );
   233	  }
   234	}
   235	
