   239	  final String description;
   240	
   241	  const _InfoRow({
   242	    required this.status,
   243	    required this.color,
   244	    required this.description,
   245	  });
   246	
   247	  @override
   248	  Widget build(BuildContext context) {
   249	    return Padding(
   250	      padding: const EdgeInsets.symmetric(vertical: 4),
   251	      child: Row(
   252	        children: [
   253	          Container(
   254	            width: 16,
   255	            height: 16,
   256	            decoration: BoxDecoration(color: color, shape: BoxShape.circle),
   257	          ),
   258	          const SizedBox(width: 12),
