  6	
  7	class CloudSettingsService {
  8	  CloudSettingsService({FirebaseFirestore? firestore, FirebaseAuth? auth})
  9	    : _firestore = firestore ?? FirebaseFirestore.instance,
 10	      _auth = auth ?? FirebaseAuth.instance;
 11	
 12	  final FirebaseFirestore _firestore;
 13	  final FirebaseAuth _auth;
 14	
 15	  User? get _user => _auth.currentUser;
 16	
 17	  Future<void> uploadLocalSettings(PrefsRepository repo) async {
 18	    final user = _user;
 19	    if (user == null || user.isAnonymous) return;
 20	
 21	    try {
 22	      final settings = repo.loadAppSettings();
 23	      await _settingsRef(user.uid).set({
 24	        ...settings.toJson(),
 25	        'syncedAt': FieldValue.serverTimestamp(),
 26	      }, SetOptions(merge: true));
 27	      await repo.setSyncPending(false);
 28	    } catch (e) {
 29	      await repo.saveSyncStatus(status: 'failed', error: e.toString());
 30	      await repo.setSyncPending(isRetryableCloudSyncError(e));
 31	      rethrow;
 32	    }
 33	  }
 34	
 35	  Future<void> syncLocalAndRemote(PrefsRepository repo) async {
 36	    try {
 37	      final user = _user;
 38	      if (user == null || user.isAnonymous) return;
 39	
 40	      final local = repo.loadAppSettings();
 41	      final snapshot = await _settingsRef(user.uid).get();
 42	      if (!snapshot.exists) {
 43	        await uploadLocalSettings(repo);
 44	        return;
 45	      }
 46	
 47	      final remote = AppSettings.fromJson(snapshot.data() ?? {});
 48	      if (_isRemoteNewer(local, remote)) {
 49	        await repo.applyAppSettings(remote);
 50	      } else {
 51	        await uploadLocalSettings(repo);
 52	      }
 53	      await repo.setSyncPending(false);
 54	    } catch (e) {
 55	      await repo.saveSyncStatus(status: 'failed', error: e.toString());
 56	      await repo.setSyncPending(isRetryableCloudSyncError(e));
 57	      rethrow;
 58	    }
 59	  }
 60	
 61	  bool _isRemoteNewer(AppSettings local, AppSettings remote) {
 62	    final localTime = DateTime.tryParse(local.updatedAt) ?? DateTime(1970);
 63	    final remoteTime = DateTime.tryParse(remote.updatedAt) ?? DateTime(1970);
 64	    return remoteTime.isAfter(localTime);
 65	  }
 66	
 67	  DocumentReference<Map<String, dynamic>> _settingsRef(String uid) {
 68	    return _firestore
 69	        .collection('users')
 70	        .doc(uid)
 71	        .collection('settings')
 72	        .doc('app');
 73	  }
 74	}
